const input = $input.first().json;
const body = input.body || input;

const workflowId = body.workflow_id || 'unknown';
const workflowName = body.workflow_name || 'unknown';
const nodeName = body.node_name || 'unknown';
const errorMessage = body.error_message || 'Unknown error';
const errorCategory = body.error_category || 'unknown';
const severity = body.severity || 'MEDIUM';
const executionId = body.execution_id || 'unknown';
const executionUrl = body.execution_url || '';
const isTransient = body.is_transient || false;
const timestamp = body.timestamp || new Date().toISOString();

// Generate error hash for deduplication
const hashInput = workflowId + '|' + errorCategory + '|' + nodeName;
let errorHash = 0;
for (let i = 0; i < hashInput.length; i++) {
  const char = hashInput.charCodeAt(i);
  errorHash = ((errorHash << 5) - errorHash) + char;
  errorHash = errorHash & errorHash;
}
errorHash = Math.abs(errorHash).toString(16).substring(0, 12);

const ERROR_LEDGER_ID = 'JofPMjEUNrEu9lao';
const KNOWN_FIXES_ID = 'nBU0Mfop4Yqb1W7q';

let occurrenceCount = 0;
let previousFixes = [];
let strategy = 'normal';
let knownFix = null;

try {
  const ledgerResp = await this.helpers.request({
    method: 'GET',
    uri: $vars.N8N_HOST + '/api/v1/data-tables/' + ERROR_LEDGER_ID + '/rows?limit=250',
    headers: { 'X-N8N-API-KEY': $vars.N8N_INTERNAL_API_KEY },
    json: true,
    resolveWithFullResponse: false,
    simple: false
  });
  const rows = (ledgerResp && ledgerResp.data) || [];
  const matching = rows.filter(r => r.error_hash === errorHash);
  occurrenceCount = matching.length;
  previousFixes = matching.map(r => r.fix_attempted).filter(Boolean);
} catch(e) {}

try {
  const fixesResp = await this.helpers.request({
    method: 'GET',
    uri: $vars.N8N_HOST + '/api/v1/data-tables/' + KNOWN_FIXES_ID + '/rows?limit=250',
    headers: { 'X-N8N-API-KEY': $vars.N8N_INTERNAL_API_KEY },
    json: true,
    resolveWithFullResponse: false,
    simple: false
  });
  const fixes = (fixesResp && fixesResp.data) || [];
  const msgLower = errorMessage.toLowerCase();
  for (const fix of fixes) {
    if (fix.error_pattern) {
      try {
        const re = new RegExp(fix.error_pattern, 'i');
        if (re.test(msgLower) || re.test(errorCategory)) {
          knownFix = fix;
          break;
        }
      } catch(e) {}
    }
  }
} catch(e) {}

if (occurrenceCount >= 5) strategy = 'hard_escalate';
else if (occurrenceCount >= 3) strategy = 'fundamentally_different_approach';
else if (occurrenceCount >= 2) strategy = 're_research_deeper';
else strategy = 'normal';

const strategyGuide = {
  hard_escalate: '5+ recurrences. Hard escalate with full history of every fix attempted. List all previous fixes and why they failed.',
  fundamentally_different_approach: '3+ recurrences. Previous fixes failed repeatedly. Find a FUNDAMENTALLY different approach. Do NOT retry the same category of fix.',
  re_research_deeper: '2nd occurrence. Previous fix was not permanent. Research deeper — the root cause is different from what was assumed.',
  normal: 'First occurrence. Normal resolution loop.'
};

const knownFixInfo = knownFix
  ? 'MATCH FOUND: ' + knownFix.fix_id + ' — ' + knownFix.fix_description + '\nDocs: ' + (knownFix.docs_reference || 'none') + '\nConfidence: ' + knownFix.confidence
  : 'No known fix matched. Research required.';

const prevFixInfo = previousFixes.length > 0
  ? previousFixes.map((f, i) => 'Fix #' + (i+1) + ': ' + f).join('\n')
  : 'None — first occurrence.';

const systemPrompt = `You are RESPONDER — the Ascend GTM Platform reactive recovery agent. Your ONLY job is to RESOLVE errors on the n8n platform.

## SELF-HEALING SLA (MANDATORY)
Every error MUST follow this loop:
1. DETECT — error received (done — see context)
2. CLASSIFY — known pattern or unknown? Check known fix info below
3. RESEARCH — use the Gateway tool to read platform docs, check workflow configs. For n8n issues, research via the Gateway's handover domain
4. FIX — apply permanent fix. Use Gateway tool with domain=handover, action=safe_modify_workflow for workflow changes
5. TARGETED TEST — verify the fix. Test the specific endpoint or workflow that failed
6. REGRESSION TEST — test related functionality that could be affected
7. CONFIRM — only after both tests pass, status=RESOLVED

## VALID FINAL STATES
- RESOLVED: Fix applied and both tests passed
- ESCALATED: With valid reason ONLY: UI-only OAuth re-auth, billing decisions, architecture affecting multiple tenants, 3rd-party outage, 5+ recurrences after research-backed fixes
- "Alert sent" is NEVER valid. You MUST attempt a fix.

## RECURRENCE STRATEGY: ${strategy.toUpperCase()} (occurrence #${occurrenceCount + 1})
${strategyGuide[strategy]}

## KNOWN FIX
${knownFixInfo}

## PREVIOUS FIXES ATTEMPTED
${prevFixInfo}

## PLATFORM CONSTRAINTS
- Code node HTTP: this.helpers.request() only
- DataTable: INSERT + READ only. No row update/delete via API
- Workflow updates: handover.safe_modify_workflow (GET+modify+PUT+snapshot)
- NEVER add Execute Workflow nodes in error handlers
- Gateway: POST /webhook/orchestrate-v2 with {domain, action, client, params}

## YOUR TOOLS
- **Ascend Gateway**: Call domain=handover for platform ops (safe_modify_workflow, list_workflows, read_rows, datatable_insert, log_change)
- **Think**: Plan your approach before acting

## RESPONSE FORMAT
After completing the SLA loop, respond with EXACTLY this JSON:
{"status": "RESOLVED|ESCALATED", "fix_description": "what you did", "docs_consulted": "urls or references checked", "test_result": "PASS|FAIL with details", "escalation_reason": "only if ESCALATED"}`;

const agentPrompt = `ERROR CONTEXT:
- Workflow: ${workflowName} (${workflowId})
- Node: ${nodeName}
- Category: ${errorCategory}
- Severity: ${severity}
- Message: ${errorMessage}
- Execution: ${executionUrl}
- Transient: ${isTransient}
- Occurrence: #${occurrenceCount + 1}
- Strategy: ${strategy}

Follow the Self-Healing SLA. Think first, then act. Respond with the JSON format specified.`;

return [{ json: {
  error_hash: errorHash,
  workflow_id: workflowId,
  workflow_name: workflowName,
  node_name: nodeName,
  error_message: errorMessage,
  error_category: errorCategory,
  severity,
  execution_id: executionId,
  execution_url: executionUrl,
  is_transient: isTransient,
  occurrence_count: occurrenceCount + 1,
  strategy,
  known_fix_id: knownFix ? knownFix.fix_id : null,
  timestamp,
  systemPrompt,
  agentPrompt
} }];

const agentOutput = $input.first().json;
const ctx = $('Enrich Error Context').first().json;

let response = agentOutput.output || agentOutput.text || '';
if (typeof response !== 'string') response = JSON.stringify(response);

let status = 'unknown';
let fixDescription = '';
let docsConsulted = '';
let testResult = '';
let escalationReason = '';

try {
  const jsonMatch = response.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    status = parsed.status || 'unknown';
    fixDescription = parsed.fix_description || '';
    docsConsulted = parsed.docs_consulted || '';
    testResult = parsed.test_result || '';
    escalationReason = parsed.escalation_reason || '';
  }
} catch(e) {
  fixDescription = response.substring(0, 500);
}

return [{ json: {
  error_hash: ctx.error_hash,
  workflow_id: ctx.workflow_id,
  workflow_name: ctx.workflow_name,
  node_name: ctx.node_name,
  error_category: ctx.error_category,
  error_message: ctx.error_message,
  severity: ctx.severity,
  occurrence_count: ctx.occurrence_count,
  status,
  fix_attempted: fixDescription,
  fix_result: testResult,
  docs_consulted: docsConsulted,
  escalation_reason: escalationReason,
  first_seen: ctx.occurrence_count <= 1 ? ctx.timestamp : '',
  last_seen: ctx.timestamp,
  responder_execution_id: $execution.id,
  response
} }];

const item = $input.first().json;
const ERROR_LEDGER_ID = 'JofPMjEUNrEu9lao';

try {
  await this.helpers.request({
    method: 'POST',
    uri: $vars.N8N_HOST + '/api/v1/data-tables/' + ERROR_LEDGER_ID + '/rows',
    headers: {
      'X-N8N-API-KEY': $vars.N8N_INTERNAL_API_KEY,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({ data: [{
      error_hash: item.error_hash,
      workflow_id: item.workflow_id,
      workflow_name: item.workflow_name,
      node_name: item.node_name,
      error_category: item.error_category,
      error_message: (item.error_message || '').substring(0, 500),
      severity: item.severity,
      occurrence_count: item.occurrence_count,
      status: item.status,
      fix_attempted: (item.fix_attempted || '').substring(0, 500),
      fix_result: (item.fix_result || '').substring(0, 200),
      docs_consulted: (item.docs_consulted || '').substring(0, 500),
      resolution_notes: item.escalation_reason || '',
      first_seen: item.first_seen || item.last_seen,
      last_seen: item.last_seen,
      responder_execution_id: item.responder_execution_id
    }] }),
    resolveWithFullResponse: false,
    simple: false
  });
} catch(e) {}

return [{ json: {
  status: item.status,
  fix_description: item.fix_attempted,
  test_result: item.fix_result,
  escalation_reason: item.escalation_reason,
  occurrence: item.occurrence_count,
  error_hash: item.error_hash
} }];
